import React, { useContext } from 'react';
import { AppContext } from '../contexts/AppContext';

function DetailBar() {
  const { selectedFrame } = useContext(AppContext);
  const {name, x, y, w, h } = selectedFrame;

  return (
    <div className="panel detail-panel">
      <div className="title title--border-bottom">Frame Detail</div>

      <div className="property-box">
        <div className="row row-hover">
          <span className="property-name">FRAME</span>
          <span className="property-value">{name ?? ''}</span>
        </div>
        <div className="row row-hover">
          <span className="property-name">X</span>
          <span className="property-value">{x ?? ''}</span>
        </div>
        <div className="row row-hover">
          <span className="property-name">Y</span>
          <span className="property-value">{y ?? ''}</span>
        </div>
        <div className="row row-hover">
          <span className="property-name">W</span>
          <span className="property-value">{w ?? ''}</span>
        </div>
        <div className="row row-hover">
          <span className="property-name">H</span>
          <span className="property-value">{h ?? ''}</span>
        </div>
      </div>

      <div className="title title--border-top">Preview</div>
      <div className="preview-box">
        <div className="preview-data">
          <div className="preview-data__transparent"></div>
          <div className="preview-data__img"></div>
        </div>
      </div>
    </div>
  )
}

export default DetailBar;