import React, { useContext, useEffect, useRef } from 'react';
import { AppContext } from '../contexts/AppContext';
import cssNames from '../utils/css-name';

function FileBar() {
  const {
    spriteDef,
    selectedFrame,
    setSelectedFrame,
    imgFileName,
    jsonFileName,
  } = useContext(AppContext);

  const fileNames = [imgFileName, jsonFileName].filter(item => item);
  const frameRef = useRef();

  const onFrameClick = (frame) => {
    setSelectedFrame(frame);
  };

  const renderRow = (frame, idx) => {
    const { name } = frame;
    const classNames = cssNames({
      'row': true,
      'row-hover': true,
      'row-hover--active': name === selectedFrame?.name,
    });
    return (
      <div
        className={classNames}
        key={idx}
        onClick={() => onFrameClick(frame)}
        ref={frame === selectedFrame?.name ? frameRef : undefined}
      >
        <div className="file-name">{name}</div>
      </div>
    )
  };

  useEffect(() => {
    frameRef.current?.scrollIntoView();
  });

  return (
    <div className="panel file-panel">
      <div className="title title--border-bottom">Files</div>
      <div className="file-box">
        {fileNames.map((item, idx) => (
          <div className="row" key={idx}>
            <div className="file-name">{item}</div>
          </div>
        ))}
      </div>
      <div className="title title--border-top">Frames</div>
      <div className="frames-box">
        {spriteDef?.map((frame, idx) => renderRow(frame, idx))}
      </div>
    </div>
  )
}

export default FileBar;