import React, {
  useContext,
  useEffect,
  useRef,
  useState
} from 'react';
import { AppContext } from '../contexts/AppContext';
import { getSpriteDefFromJSON } from '../utils/sprite';
import cssNames from '../utils/css-name';

function Main() {
  const {
    setSpriteURL,
    setImgOriginWidth,
    setImgOriginHeight,
    spriteDef,
    setSpriteDef,
    spriteURL,
    imgOriginWidth,
    imgOriginHeight,
    selectedFrame,
    setSelectedFrame,
    setImgFileName,
    setJsonFileName,
  } = useContext(AppContext);
  const [contentWidth, setContentWidth] = useState();
  const [contentHeight, setContentHeight] = useState();
  const workspaceRef = useRef();

  const onDragOver = (e) => {
    e.preventDefault();
  };

  const onDragEnter = (e) => {
    e.preventDefault();
  };

  const onDragLeave = (e) => {
    e.preventDefault();
  };

  const onDrop = async (e) => {
    e.preventDefault();

    [...e.dataTransfer.items].forEach(async (item) => {
      const file = item.getAsFile();
      const fileName = file.name;

      if (item.type.match('image')) {
        const objectURL = URL.createObjectURL(file);
        const img = document.createElement('img');
        img.onload = () => {
          setImgOriginWidth(img.width);
          setImgOriginHeight(img.height);
        };
        img.src = objectURL;
        setImgFileName(fileName);
        setSpriteURL(objectURL);
      }

      if (item.type.match('json')) {
        const json = await file.text();
        const sprite = getSpriteDefFromJSON(json);
        setJsonFileName(fileName);
        setSpriteDef(sprite);
      }
    });
  };

  useEffect(() => {
    const workspace = workspaceRef.current;
    setContentWidth(workspace.offsetWidth);
    setContentHeight(workspace.offsetHeight);
  }, [contentWidth, contentHeight]);

  const renderSpriteSelector = (frame, idx) => {
    const { name, x, y, w, h } = frame;
    const classNames = cssNames({
      'sprite-selector': true,
      'sprite-selector--active': name === selectedFrame?.name,
    });
    return (
      <div
        className={classNames}
        style={{ top: y, left: x, width: w, height: h, }}
        onClick={() => onFrameClick(frame)}
        key={idx}
      ></div>
    )
  };

  const onFrameClick = (frame) => {
    setSelectedFrame(frame);
  };

  return (
    <div
      className="workspace"
      ref={workspaceRef} {...{
        onDragEnter,
        onDragOver,
        onDragLeave,
        onDrop,
      }}
    >
      <div
        className="sprite-wrap"
        style={{
          width: imgOriginWidth,
          height: imgOriginHeight,
        }}
      >
        <div
          className="sprite-img"
          style={{ backgroundImage: `url("${spriteURL}")` }}
        ></div>
        {spriteDef?.map((frame, idx) => renderSpriteSelector(frame, idx))}
      </div>
    </div>
  )
}

export default Main;